// Replace QrScanner definition
function QrScannerComponent({ onScan }) {
  const [devices, setDevices] = useState([]);
  const [selectedDeviceId, setSelectedDeviceId] = useState('');

  useEffect(() => {
    async function getDevices() {
      if (navigator.mediaDevices && navigator.mediaDevices.enumerateDevices) {
        const allDevices = await navigator.mediaDevices.enumerateDevices();
        const videoDevices = allDevices.filter(d => d.kind === 'videoinput');
        setDevices(videoDevices);
        // Default: back camera on mobile, front on desktop
        const isMobile = /Android|iPhone|iPad|iPod/i.test(navigator.userAgent);
        let preferred = videoDevices[0]?.deviceId || '';
        for (const d of videoDevices) {
          if (isMobile && d.label.toLowerCase().includes('back')) preferred = d.deviceId;
          if (!isMobile && d.label.toLowerCase().includes('front')) preferred = d.deviceId;
        }
        setSelectedDeviceId(preferred);
      }
    }
    getDevices();
  }, []);

  const handleScan = data => {
    if (data) onScan(data.text || data);
  };
  const handleError = err => {
    // Optionally handle error
  };

  return (
    <div style={{ maxWidth: 350, margin: '0 auto', marginBottom: 16 }}>
      {devices.length > 1 && (
        <select value={selectedDeviceId} onChange={e => setSelectedDeviceId(e.target.value)} style={{ marginBottom: 8, width: '100%' }}>
          {devices.map(d => (
            <option key={d.deviceId} value={d.deviceId}>{d.label || `Camera ${d.deviceId}`}</option>
          ))}
        </select>
      )}
      <QrScanner
        delay={300}
        onError={handleError}
        onScan={handleScan}
        style={{ width: '100%' }}
        constraints={{
          video: selectedDeviceId ? { deviceId: { exact: selectedDeviceId } } : { facingMode: /Android|iPhone|iPad|iPod/i.test(navigator.userAgent) ? 'environment' : 'user' }
        }}
      />
    </div>
  );
}

function SecondaryAdminUpdateDuty() {
  useSessionTimeout();
  const email = localStorage.getItem('adminEmail') || 'Secondary Admin';
  const navigate = useNavigate();
  const [users, setUsers] = React.useState([]);
  const [selectedId, setSelectedId] = React.useState('');
  const [selectedUser, setSelectedUser] = React.useState(null);
  const [comingTime, setComingTime] = React.useState('');
  const [finishingTime, setFinishingTime] = React.useState('');
  const [successMsg, setSuccessMsg] = React.useState('');
  const [errorMsg, setErrorMsg] = React.useState('');
  const [date, setDate] = React.useState(dayjs().format('YYYY-MM-DD'));
  const [attendance, setAttendance] = React.useState([]);
  const [showScanner, setShowScanner] = React.useState(false);
  const [dutySchedule, setDutySchedule] = React.useState('');

  React.useEffect(() => {
    async function fetchUsers() {
      try {
        const token = localStorage.getItem('token');
        const res = await fetch(`${API_URL}/api/users`, {
          headers: { 'Authorization': `Bearer ${token}` },
        });
        const data = await res.json();
        if (res.ok) setUsers(data);
      } catch {}
    }
    fetchUsers();
  }, []);

  React.useEffect(() => {
    async function fetchUserDetails() {
      if (selectedId) {
        const token = localStorage.getItem('token');
        const res = await fetch(`${API_URL}/api/users/${selectedId}`, {
          headers: { 'Authorization': `Bearer ${token}` },
        });
        const data = await res.json();
        if (res.ok) {
          setSelectedUser(data);
          setAttendance(data.attendance || []);
        } else {
          setSelectedUser(null);
          setAttendance([]);
        }
      } else {
        setSelectedUser(null);
        setAttendance([]);
      }
      setComingTime('');
      setFinishingTime('');
      setSuccessMsg('');
      setErrorMsg('');
    }
    fetchUserDetails();
  }, [selectedId]);

  React.useEffect(() => {
    // Set coming/finishing time for selected date if exists
    if (attendance && date) {
      const att = attendance.find(a => a.date === date);
      setComingTime(att?.comingTime || '');
      setFinishingTime(att?.finishingTime || '');
    }
  }, [date, attendance]);

  const handleUpdateComing = async (e) => {
    e.preventDefault();
    setSuccessMsg('');
    setErrorMsg('');
    if (!selectedId) return setErrorMsg('Please select a user.');
    if (!date) return setErrorMsg('Please select a date.');
    if (!comingTime) return setErrorMsg('Please enter coming time.');
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_URL}/api/users/${selectedId}/duty`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ date, comingTime, dutySchedule }),
      });
      const data = await res.json();
      if (res.ok) {
        setSuccessMsg('Coming time updated successfully!');
        setTimeout(() => setSuccessMsg(''), 2000);
        // Refresh user details
        const userRes = await fetch(`${API_URL}/api/users/${selectedId}`, {
          headers: { 'Authorization': `Bearer ${token}` },
        });
        const userData = await userRes.json();
        if (userRes.ok) {
          setSelectedUser(userData);
          setAttendance(userData.attendance || []);
        }
      } else {
        setErrorMsg(data.message || 'Failed to update coming time');
      }
    } catch {
      setErrorMsg('Failed to update coming time');
    }
  };

  const handleUpdateFinishing = async (e) => {
    e.preventDefault();
    setSuccessMsg('');
    setErrorMsg('');
    if (!selectedId) return setErrorMsg('Please select a user.');
    if (!date) return setErrorMsg('Please select a date.');
    if (!finishingTime) return setErrorMsg('Please enter finishing time.');
    // Check if comingTime exists and is before finishingTime
    if (comingTime && finishingTime) {
      const [ch, cm] = comingTime.split(':').map(Number);
      const [fh, fm] = finishingTime.split(':').map(Number);
      const start = ch * 60 + cm;
      const end = fh * 60 + fm;
      if (end <= start) {
        setErrorMsg('Finishing time must be after coming time.');
        return;
      }
    }
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_URL}/api/users/${selectedId}/duty`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ date, finishingTime, dutySchedule }),
      });
      const data = await res.json();
      if (res.ok) {
        setSuccessMsg('Finishing time updated successfully!');
        setTimeout(() => setSuccessMsg(''), 2000);
        // Refresh user details
        const userRes = await fetch(`${API_URL}/api/users/${selectedId}`, {
          headers: { 'Authorization': `Bearer ${token}` },
        });
        const userData = await userRes.json();
        if (userRes.ok) {
          setSelectedUser(userData);
          setAttendance(userData.attendance || []);
        }
      } else {
        setErrorMsg(data.message || 'Failed to update finishing time');
      }
    } catch {
      setErrorMsg('Failed to update finishing time');
    }
  };

  const attendanceColumns = [
    { title: 'Date', dataIndex: 'date', key: 'date' },
    { title: 'Coming Time', dataIndex: 'comingTime', key: 'comingTime' },
    { title: 'Finishing Time', dataIndex: 'finishingTime', key: 'finishingTime' },
    { 
      title: 'Duty Time', 
      key: 'dutyTime',
      render: (_, record) => {
        if (record.comingTime && record.finishingTime) {
          const start = dayjs(`${record.date} ${record.comingTime}`, "YYYY-MM-DD HH:mm");
          const end = dayjs(`${record.date} ${record.finishingTime}`, "YYYY-MM-DD HH:mm");
          if (start.isValid() && end.isValid()) {
            const minutes = end.diff(start, 'minute');
            const hours = Math.floor(minutes / 60);
            const remainingMinutes = minutes % 60;
            return `${hours}h ${remainingMinutes}m`;
          }
        }
        return '-';
      }
    },
  ];

  const handleQrScan = async (scannedText) => {
    if (!scannedText) return;
    // Assume QR code contains the user profile link or just the user ID
    let userId = scannedText;
    // If QR code is a URL, extract the user ID
    const match = scannedText.match(/\/user\/([\w-]+)/);
    if (match) userId = match[1];
    setSelectedId(userId);
    // Fetch user details and auto-update coming/finishing time
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${API_URL}/api/users/${userId}`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) {
        setSelectedUser(data);
        setAttendance(data.attendance || []);
        const today = dayjs().format('YYYY-MM-DD');
        const todayRecord = (data.attendance || []).find(a => a.date === today);
        if (!todayRecord || !todayRecord.comingTime) {
          // Auto-update coming time
          const now = dayjs().format('HH:mm');
          await fetch(`${API_URL}/api/users/${userId}/duty`, {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`,
            },
            body: JSON.stringify({ date: today, comingTime: now, dutySchedule }),
          });
          setComingTime(now);
          setSuccessMsg('Coming time updated automatically!');
          setShowScanner(false);
        } else if (todayRecord.comingTime && !todayRecord.finishingTime) {
          // Auto-update finishing time
          const now = dayjs().format('HH:mm');
          await fetch(`${API_URL}/api/users/${userId}/duty`, {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`,
            },
            body: JSON.stringify({ date: today, finishingTime: now, dutySchedule }),
          });
          setFinishingTime(now);
          setSuccessMsg('Finishing time updated automatically!');
          setShowScanner(false);
        } else {
          setSuccessMsg('Your attendance is already marked.');
          setShowScanner(false);
        }
      } else {
        setErrorMsg(data.message || 'User not found');
      }
    } catch (err) {
      setErrorMsg('Failed to fetch user details');
    } finally {
      // setQrScanLoading(false); // Removed as per edit hint
    }
  };

  return (
    <Layout style={{ minHeight: '100vh' }}>
      <Sider breakpoint="lg" collapsedWidth="0">
        <img
          src={process.env.PUBLIC_URL + '/IMG-20230930-WA0000-removebg-preview.png'}
          alt="Scout Logo"
          style={{ width: 100, height: 100, objectFit: 'contain', display: 'block', margin: '24px auto', padding: 0 }}
        />
        <Menu
          theme="dark"
          mode="inline"
          defaultSelectedKeys={['update']}
          onClick={({ key }) => {
            if (key === 'overview') navigate('/dashboard/secondary');
            if (key === 'view-users') navigate('/dashboard/secondary/view-users');
            if (key === 'update') navigate('/dashboard/secondary/update-duty');
            if (key === 'attendance-history') navigate('/dashboard/secondary/attendance-history');
          }}
          items={[
            { key: 'overview', label: 'Overview' },
            { key: 'view-users', label: 'View Users' },
            { key: 'update', label: 'Update Duty Times' },
            { key: 'attendance-history', label: 'Attendance History' },
          ]}
        />
      </Sider>
      <Layout>
        <Header style={{ background: '#fff', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <b>{email}</b> <span style={{ color: '#1677ff', marginLeft: 8 }}>[secondary]</span>
          </div>
          <Button type="primary" danger style={{ background: '#ff4d4f', borderColor: '#ff4d4f' }} onClick={logout}>Logout</Button>
        </Header>
        <Content style={{ margin: 0, background: 'transparent', minHeight: 400, padding: 0 }}>
          <div className="user-status-bg" style={{ minHeight: '100vh', padding: 0 }}>
            <div style={{ maxWidth: 600, margin: '0 auto', padding: '40px 0' }}>
              <div className="glass-card" style={{ padding: 32, borderRadius: 24, boxShadow: '0 8px 32px 0 rgba(31, 38, 135, 0.10)' }}>
                <h2 style={{ textAlign: 'center', fontWeight: 800, fontSize: 32, letterSpacing: 1, color: '#00cec8', marginBottom: 32, animation: 'fadeIn 1s' }}>Update Duty Times</h2>
                <form onSubmit={handleUpdateComing} style={{ maxWidth: 500, margin: '0 auto' }}>
                  <div style={{ marginBottom: 20 }}>
                    <label style={{ fontWeight: 600, color: '#006064' }}>User ID *</label><br />
                    <select value={selectedId} onChange={e => setSelectedId(e.target.value)} style={{ width: '100%', padding: 10, borderRadius: 10, border: '1.5px solid #00cec8', fontSize: 16, background: '#f7faff' }}>
                      <option value="">Select a user</option>
                      {users.map(u => <option key={u._id} value={u._id}>{u._id} - {u.name}</option>)}
                    </select>
                  </div>
                  <div style={{ marginBottom: 20 }}>
                    <label style={{ fontWeight: 600, color: '#006064' }}>Date *</label><br />
                    <DatePicker
                      value={date ? dayjs(date) : null}
                      onChange={d => setDate(d ? d.format('YYYY-MM-DD') : '')}
                      style={{ width: '100%', borderRadius: 10, fontSize: 16 }}
                      format="YYYY-MM-DD"
                      allowClear={false}
                      disabledDate={d => d && d.isAfter(dayjs(), 'day')}
                    />
                  </div>
                  {selectedUser && (
                    <div style={{ marginBottom: 20, background: '#fff', borderRadius: 16, padding: 20, boxShadow: '0 2px 12px #e6f7ff', display: 'flex', alignItems: 'center', gap: 20 }}>
                      <div className="avatar-glow">
                        {selectedUser.profilePic ? (
                          <img src={selectedUser.profilePic} alt="Profile" style={{ width: 64, height: 64, borderRadius: '50%', border: '3px solid #00cec8', boxShadow: '0 0 0 4px #00cec855, 0 4px 24px #00cec822' }} />
                        ) : (
                          <div style={{ width: 64, height: 64, borderRadius: '50%', background: '#e0fcf7', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, color: '#00cec8', fontSize: 28 }}>?</div>
                        )}
                      </div>
                      <div>
                        <b>Name:</b> {selectedUser.name}<br />
                        <b>Email:</b> {selectedUser.email}<br />
                        <b>Phone:</b> {selectedUser.phoneNumber}<br />
                        <b>NIC:</b> {selectedUser.nic}<br />
                        <b>Current Duty Time:</b> {selectedUser.dutyTime} min
                      </div>
                    </div>
                  )}
                  <div style={{ marginBottom: 20 }}>
                    <label style={{ fontWeight: 600, color: '#006064' }}>Coming Time</label><br />
                    <input type="time" value={comingTime} onChange={e => setComingTime(e.target.value)} style={{ width: '100%', padding: 10, borderRadius: 10, border: '1.5px solid #00cec8', fontSize: 16 }} />
                    <button onClick={handleUpdateComing} className="copy-link-btn" style={{ marginTop: 10, width: '100%' }}>Update Coming Time</button>
                  </div>
                  {comingTime && (
                    <div style={{ marginBottom: 20 }}>
                      <label style={{ fontWeight: 600, color: '#006064' }}>Finishing Time</label><br />
                      <input type="time" value={finishingTime} onChange={e => setFinishingTime(e.target.value)} style={{ width: '100%', padding: 10, borderRadius: 10, border: '1.5px solid #00cec8', fontSize: 16 }} />
                      <button onClick={handleUpdateFinishing} className="copy-link-btn" style={{ marginTop: 10, width: '100%' }}>Update Finishing Time</button>
                    </div>
                  )}
                  {errorMsg && <div style={{ color: 'red', marginBottom: 12, fontWeight: 600 }}>{errorMsg}</div>}
                  {successMsg && <div style={{ color: 'green', marginBottom: 12, fontWeight: 600 }}>{successMsg}</div>}
                  <Form.Item label={<span style={{ fontWeight: 600, color: '#006064' }}>Duty Schedule</span>} style={{ marginBottom: 20 }}>
                    <Select
                      value={dutySchedule}
                      onChange={value => {
                        setDutySchedule(value);
                        if (value === 'Early Morning') {
                          setComingTime('04:30');
                          setFinishingTime('07:30');
                        } else if (value === 'Morning') {
                          setComingTime('08:00');
                          setFinishingTime('11:00');
                        } else if (value === 'Evening') {
                          setComingTime('15:30');
                          setFinishingTime('19:30');
                        } else {
                          setComingTime('');
                          setFinishingTime('');
                        }
                      }}
                      placeholder="Select a schedule"
                      style={{ width: '100%', borderRadius: 10, fontSize: 16 }}
                      allowClear
                    >
                      <Select.Option value="Early Morning">Early Morning (4:30 AM – 7:30 AM)</Select.Option>
                      <Select.Option value="Morning">Morning (8:00 AM – 11:00 AM)</Select.Option>
                      <Select.Option value="Evening">Evening (3:30 PM – 7:30 PM)</Select.Option>
                    </Select>
                  </Form.Item>
                </form>
                {/* Selected User Attendance Records */}
                {attendance && attendance.length > 0 && (
                  <div style={{ maxWidth: 700, margin: '40px auto 0 auto' }}>
                    <h3 style={{ fontWeight: 700, color: '#00cec8', marginBottom: 16 }}>Selected User Attendance Records</h3>
                    <Table columns={attendanceColumns} dataSource={attendance} rowKey="date" className="glass-card" />
                  </div>
                )}
                <Button onClick={() => setShowScanner(s => !s)} className="copy-link-btn" style={{ marginBottom: 16, width: '100%' }}>
                  {showScanner ? 'Hide' : 'Show'} QR Scanner
                </Button>
                {showScanner && <QrScannerComponent onScan={handleQrScan} />}
              </div>
            </div>
          </div>
        </Content>
      </Layout>
    </Layout>
  );
}
